/**
 * Core type definitions for @munesoft/loopx
 */
/**
 * Reasons why a loop terminated.
 */
type StopReason = "manual" | "max_iterations" | "timeout" | "stop_condition" | "completed" | "error" | "aborted" | "stagnation" | "controller_stop";
/**
 * The Step object passed to each iteration of the loop body.
 */
interface Step<TState = Record<string, unknown>, TData = unknown> {
    /** Current iteration count (0-indexed). */
    readonly iteration: number;
    /** Shared mutable state across iterations. */
    state: TState;
    /** AbortSignal that fires when the loop is stopping. */
    readonly signal: AbortSignal;
    /** Data passed from the previous iteration via step.next(). */
    readonly data: TData | undefined;
    /** Stop the loop immediately. Optional reason for observability. */
    stop(reason?: string): void;
    /** Pass data to the next iteration. */
    next(data: TData): void;
    /** Returns true if the loop has been signaled to stop. */
    readonly stopped: boolean;
}
/**
 * The function executed on each iteration of the loop.
 */
type LoopFn<TState = Record<string, unknown>, TData = unknown, TResult = void> = (step: Step<TState, TData>) => Promise<TResult> | TResult;
/**
 * Hooks fired at lifecycle points of the loop.
 */
interface LoopHooks<TState = Record<string, unknown>, TData = unknown> {
    /** Called once before the first iteration. */
    onStart?: () => void | Promise<void>;
    /** Called before each iteration with the step object. */
    onStep?: (step: Step<TState, TData>) => void | Promise<void>;
    /** Called when the loop stops, with the stop reason. */
    onStop?: (reason: StopReason, details?: string) => void | Promise<void>;
    /** Called when an iteration throws. Return truthy to suppress and continue. */
    onError?: (error: unknown, step: Step<TState, TData>) => void | boolean | Promise<void | boolean>;
    /** Called after the loop fully completes with the final result. */
    onComplete?: (result: LoopResult<TState>) => void | Promise<void>;
}
/**
 * Configuration options for loopx().
 */
interface LoopOptions<TState = Record<string, unknown>, TData = unknown> extends LoopHooks<TState, TData> {
    /** Hard cap on iterations. Defaults to 1000 to prevent runaway loops. */
    maxIterations?: number;
    /** Timeout in milliseconds. Stops the loop when exceeded. */
    timeout?: number;
    /** Predicate evaluated each iteration; return true to stop. */
    stop?: (step: Step<TState, TData>) => boolean | Promise<boolean>;
    /** Initial state object — copied into step.state. */
    initialState?: TState;
    /** Delay in ms between iterations. */
    delay?: number;
    /** Number of times to retry an iteration on error before giving up. */
    retry?: number;
    /** External AbortSignal — aborting it stops the loop. */
    signal?: AbortSignal;
    /**
     * AI / smart-stop mode. When true, detects repetitive outputs (stagnation)
     * across iterations using step.next() data and stops the loop.
     */
    ai?: boolean;
    /** Number of identical consecutive outputs that count as stagnation (default 3). */
    stagnationThreshold?: number;
}
/**
 * The final result returned from a loop.
 */
interface LoopResult<TState = Record<string, unknown>> {
    /** Total number of iterations that ran. */
    iterations: number;
    /** Why the loop stopped. */
    reason: StopReason;
    /** Optional human-readable detail about the stop reason. */
    detail?: string;
    /** The final state. */
    state: TState;
    /** Total elapsed time in ms. */
    elapsedMs: number;
    /** Error that ended the loop, if any. */
    error?: unknown;
}
/**
 * A controller returned by loopx.controller() for pause/resume/stop.
 */
interface LoopController<TState = Record<string, unknown>, TData = unknown> {
    /** Run the loop with the given function and options. */
    run(fn: LoopFn<TState, TData>, options?: LoopOptions<TState, TData>): Promise<LoopResult<TState>>;
    /** Pause execution between iterations. */
    pause(): void;
    /** Resume a paused loop. */
    resume(): void;
    /** Stop the loop immediately. */
    stop(reason?: string): void;
    /** True if currently paused. */
    readonly paused: boolean;
    /** True if currently running. */
    readonly running: boolean;
}

/**
 * @munesoft/loopx — Universal loop controller for AI agents and async workflows.
 *
 * Primary API:
 *   await loopx(async (step) => { ... });
 *   await loopx(async (step) => { ... }, { maxIterations: 10 });
 *   const c = loopx.controller(); await c.run(async (step) => { ... });
 */

/**
 * Run a loop. Each iteration calls `fn` with a fresh `step` object.
 *
 * The loop stops when any of these happen:
 *   - the body calls step.stop()
 *   - maxIterations is reached (defaults to 1000 as a safety net)
 *   - timeout elapses
 *   - the stop predicate returns true
 *   - an external AbortSignal aborts
 *   - the body throws and isn't suppressed by onError
 *   - ai mode detects stagnation in step.next() data
 *
 * @example
 * ```ts
 * await loopx(async (step) => {
 *   if (step.iteration >= 5) step.stop();
 * });
 * ```
 */
declare function loopx<TState extends Record<string, unknown> = Record<string, unknown>, TData = unknown>(fn: LoopFn<TState, TData>, options?: LoopOptions<TState, TData>): Promise<LoopResult<TState>>;
/**
 * Create a controller for pause / resume / stop control over a loop.
 *
 * @example
 * ```ts
 * const c = loopx.controller();
 * const done = c.run(async (step) => { ... });
 * c.pause();
 * c.resume();
 * await done;
 * ```
 */
declare function controller<TState extends Record<string, unknown> = Record<string, unknown>, TData = unknown>(): LoopController<TState, TData>;
type LoopxFn = typeof loopx & {
    controller: typeof controller;
};
declare const _default: LoopxFn;

export { type LoopController, type LoopFn, type LoopHooks, type LoopOptions, type LoopResult, type Step, type StopReason, controller, _default as default, loopx };
